import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';

const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, handleLogout }) => {
    const location = useLocation();
    const [hoveredMenu, setHoveredMenu] = useState(null);

    // Fungsi navigasi dengan pengecekan prop
    const navigateTo = (menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
    };

    // Style umum untuk item menu
    const getMenuStyle = (menuId) => ({
        background: 'none',
        border: 'none',
        fontSize: '14px',
        fontWeight: '700',
        cursor: 'pointer',
        transition: 'all 0.3s ease',
        textDecoration: 'none',
        // Jika sedang aktif ATAU sedang di-hover, beri warna accent
        color: (activeMenu === menuId || hoveredMenu === menuId) ? '#ea580c' : '#fff',
        // Efek underline untuk menu aktif
        borderBottom: activeMenu === menuId ? '2px solid #ea580c' : '2px solid transparent',
        paddingBottom: '4px'
    });

    return (
        <nav style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            padding: '20px 80px', 
            background: '#0c0a09', 
            borderBottom: '1px solid #262626' 
        }}>
            <div onClick={() => navigateTo('home')} style={{ cursor: 'pointer' }}>
                <h1 style={{ color: '#ea580c', margin: 0, fontSize: '24px' }}>PasukanYerusSolo</h1>
            </div>

            <div style={{ display: 'flex', gap: '24px', alignItems: 'center' }}>

                <Link 
                    to="/" 
                    style={getMenuStyle('home')}
                    onMouseEnter={() => setHoveredMenu('home')}
                    onMouseLeave={() => setHoveredMenu(null)}
                    onClick={() => navigateTo('home')}
                >
                    Home
                </Link>

                <button 
                    style={getMenuStyle('eksplorasi')}
                    onMouseEnter={() => setHoveredMenu('eksplorasi')}
                    onMouseLeave={() => setHoveredMenu(null)}
                    onClick={() => navigateTo('eksplorasi')}
                >
                    Eksplorasi
                </button>

                {isAuthenticated ? (
                    <>
                        <button style={getMenuStyle('favorit')} onMouseEnter={() => setHoveredMenu('favorit')} onMouseLeave={() => setHoveredMenu(null)} onClick={() => navigateTo('favorit')}>Favorit</button>
                        <button style={getMenuStyle('status')} onMouseEnter={() => setHoveredMenu('status')} onMouseLeave={() => setHoveredMenu(null)} onClick={() => navigateTo('status')}>Status</button>
                        <button onClick={handleLogout} style={{ padding: '8px 20px', borderRadius: '20px', border: '1px solid #ef4444', background: 'transparent', color: '#ef4444', fontWeight: '700', cursor: 'pointer' }}>Keluar</button>
                    </>
                ) : (
                    <button 
                        onClick={() => window.location.href = '/login'}
                        style={{ padding: '8px 20px', borderRadius: '20px', border: '1px solid #ea580c', background: 'transparent', color: '#ea580c', fontWeight: '700', cursor: 'pointer' }}
                    >
                        Login
                    </button>
                )}
            </div>
        </nav>
    );
};

export default Navbar;
